import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;

import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.CSVParser;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.MockedConstruction;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testParse_withValidReader_shouldReturnCSVParser() throws IOException {
        Reader mockReader = mock(Reader.class);
        try (MockedConstruction<CSVParser> mocked = Mockito.mockConstruction(CSVParser.class,
                (mock, context) -> {
                    // no-op: just mock construction
                })) {
            CSVParser parser = csvFormat.parse(mockReader);
            assertNotNull(parser);
            // verify CSVParser constructor called with correct args
            assertEquals(1, mocked.constructed().size());
            CSVParser constructedParser = mocked.constructed().get(0);
            assertSame(constructedParser, parser);
        }
    }

    @Test
    void testParse_withNullReader_shouldThrowNullPointerException() {
        assertThrows(NullPointerException.class, () -> {
            csvFormat.parse(null);
        });
    }
}
